update  t_asset_scrap
    set status = #{status}
    where scrap_id in

    #{item}

mapper.select:
SELECT t_asset_scrap.*, t_employee.actual_name as applyUserName, t_employee.department_id as department_id, t_department.name as department_name FROM t_asset_scrap left join t_employee on t_asset_scrap.apply_user_id = t_employee.employee_id left join t_department on t_employee.department_id = t_department.department_id
AND ( INSTR(t_asset_scrap.scrap_code,#{queryForm.keywords}) or INSTR(t_employee.actual_name,#{queryForm.keywords}) )
AND t_employee.department_id in
#{item}
AND DATE_FORMAT(t_asset_scrap.scrap_time, '%Y-%m-%d') >= #{queryForm.scrapTimeBegin}
AND DATE_FORMAT(t_asset_scrap.scrap_time, '%Y-%m-%d') <= #{queryForm.scrapTimeEnd}
AND t_asset_scrap.enterprise_id = #{queryForm.enterpriseId}
order by t_asset_scrap.create_time desc
